async function decode(e){let t;try{t=new AudioContext({sampleRate:3e3})}catch(e){t=new AudioContext({sampleRate:8e3})}const o=t.decodeAudioData(e);return o.finally(()=>t.close()),o}function createBuffer(t,e){if((t="number"==typeof t[0]?[t]:t)[0].some(e=>1<e||e<-1)){const o=Math.max(...t[0]);t=t.map(e=>e.map(e=>e/o))}return{length:t[0].length,duration:e,numberOfChannels:t.length,sampleRate:t[0].length/e,getChannelData:e=>t?.[e],copyFromChannel:AudioBuffer.prototype.copyFromChannel,copyToChannel:AudioBuffer.prototype.copyToChannel}}const Decoder={decode:decode,createBuffer:createBuffer};export default Decoder;